// Full solution code
#include <iostream>
#include <vector>
#include <unordered_set>
#include <unordered_map>

using namespace std;

class Solution {
 public:
   bool detectCycle(vector<unordered_map<char, vector<char>>> &graph) {
    unordered_set<char> visited;
    for (auto &node : graph) {
      if (!visited.count(node.first)) {
        if (detectCycleUtil(node, visited, nullptr)) return true;
      }
    }
    return false;
   }

   bool detectCycleUtil(const unordered_map<char, vector<char>> &node, unordered_set<char> &visited, char *parent) {
    char nodeKey = node.first;
    visited.insert(nodeKey);
    for (const auto &neighbor : node) {
      if (!visited.count(neighbor.first)) {
        if (detectCycleUtil(neighbor, visited, &neighbor.first)) return true;
      } else if (parent != nullptr && *parent == neighbor.first) {
        return true;
      }
    }
    return false;
   }
};

int main() {
  Solution solution;
  vector<unordered_map<char, vector<char>>> graph;
  // Initialize graph with nodes and edges
  // Example usage
  cout << (solution.detectCycle(graph) ? "True" : "False") << endl;
  return 0;
}
